class Solution {
public:
    bool checkRecord(string s) {
        int a = 0, l = 0;
        for (char c : s) {
            if (c == 'A') { if (++a > 1) return false; l = 0; }
            else if (c == 'L') { if (++l >= 3) return false; }
            else l = 0;
        }
        return true;
    }
};
